import os
from fastapi import FastAPI
from azure.identity import DefaultAzureCredential
from azure.keyvault.secrets import SecretClient
import psycopg2

app = FastAPI()

# DefaultAzureCredential uses the managed identity on App Service
# Falls back to CLI login in local development
credential = DefaultAzureCredential()

VAULT_URL = os.environ["KEY_VAULT_URL"]  # e.g. https://myapp-kv.vault.azure.net/
secret_client = SecretClient(vault_url=VAULT_URL, credential=credential)

def get_db_connection():
    """Retrieve DB password from Key Vault at runtime."""
    secret = secret_client.get_secret("db-password")
    return psycopg2.connect(
        host=os.environ["DATABASE_HOST"],
        dbname="appdb",
        user="dbadmin",
        password=secret.value,
        sslmode="require",
    )

@app.get("/health")
def health():
    return {"status": "ok"}

@app.get("/users/{user_id}")
def get_user(user_id: int):
    with get_db_connection() as conn:
        with conn.cursor() as cur:
            cur.execute("SELECT id, email, created_at FROM users WHERE id = %s", (user_id,))
            row = cur.fetchone()
    if row is None:
        return {"error": "not found"}, 404
    return {"id": row[0], "email": row[1], "created_at": str(row[2])}
